1	/**
2	 * Per-tool grammar — spec §16.4 / §16.5.
3	 *
4	 * Each tool's interaction model is captured here as plain data so the
5	 * tool can be unit-tested without DOM. The shape is consistent across
6	 * tools so the canvas can switch on `kind` and dispatch input.
7	 */
8	
9	export type { WallLocationLine } from '@bim-ai/core';
10	import type { WallLocationLine } from '@bim-ai/core';
11	
12	/* ────────────────────────────────────────────────────────────────────── */
13	/* EDT-06 — Tool grammar polish (Chain / Multiple / Tag-on-Place /        */
14	/*           Numeric input). The canvas wires the per-tool reducers in    */
15	/*           this file plus a top-level `ToolGrammarModifiers` block      */
16	/*           that feeds the Options Bar.                                  */
17	/* ────────────────────────────────────────────────────────────────────── */
18	
19	/** Modifiers that the canvas Options Bar exposes to the user. */
20	export interface ToolGrammarModifiers {
21	  /** Place Wall continues from the last endpoint until Esc / different tool. */
22	  chainable: boolean;
23	  /** Insert Door / Window stays in tool until Esc; otherwise exits after first placement. */
24	  multipleable: boolean;
25	  /** During wall / door / window placement, auto-place a tag of the configured family. */
26	  tagOnPlace: { enabled: boolean; tagFamilyId?: string };
27	  /** Numeric input mode: typing a digit while drawing pops a numeric input field. */
28	  numericInputActive: boolean;
29	  /**
30	   * Wall draw offset — when non-zero, the wall baseline is drawn offset from
31	   * the cursor by this many mm (positive = left side of draw direction).
32	   * F-042 parity. Default 0.
33	   */
34	  wallDrawOffsetMm: number;
35	  /**
36	   * Wall draw radius — when non-null, consecutive wall segments get a curved
37	   * corner fillet of this radius (mm). F-043 parity. Default null (sharp corners).
38	   */
39	  wallDrawRadiusMm: number | null;
40	}
41	
42	export function defaultToolGrammarModifiers(): ToolGrammarModifiers {
43	  return {
44	    chainable: true,
45	    multipleable: false,
46	    tagOnPlace: { enabled: false },
47	    numericInputActive: false,
48	    wallDrawOffsetMm: 0,
49	    wallDrawRadiusMm: null,
50	  };
51	}
52	
53	/** A tool's static capability set — drives which Options Bar toggles appear. */
54	export interface ToolCapabilities {
55	  chainable: boolean;
56	  multipleable: boolean;
57	  tagOnPlace: boolean;
58	  /** Whether the tool supports typing a numeric distance while drawing. */
59	  numericInput: boolean;
60	}
61	
62	export const TOOL_CAPABILITIES: Record<string, ToolCapabilities> = {
63	  wall: {
64	    chainable: true,
65	    multipleable: false,
66	    tagOnPlace: true,
67	    numericInput: true,
68	  },
69	  door: {
70	    chainable: false,
71	    multipleable: true,
72	    tagOnPlace: true,
73	    numericInput: false,
74	  },
75	  window: {
76	    chainable: false,
77	    multipleable: true,
78	    tagOnPlace: true,
79	    numericInput: false,
80	  },
81	  beam: {
82	    chainable: false,
83	    multipleable: false,
84	    tagOnPlace: false,
85	    numericInput: true,
86	  },
87	  column: {
88	    chainable: false,
89	    multipleable: true,
90	    tagOnPlace: false,
91	    numericInput: false,
92	  },
93	  ceiling: {
94	    chainable: false,
95	    multipleable: false,
96	    tagOnPlace: false,
97	    numericInput: false,
98	  },
99	  shaft: {
100	    chainable: false,
101	    multipleable: false,
102	    tagOnPlace: false,
103	    numericInput: false,
104	  },
105	  align: {
106	    chainable: false,
107	    multipleable: false,
108	    tagOnPlace: false,
109	    numericInput: false,
110	  },
111	  split: {
112	    chainable: false,
113	    multipleable: true,
114	    tagOnPlace: false,
115	    numericInput: false,
116	  },
117	  trim: {
118	    chainable: false,
119	    multipleable: true,
120	    tagOnPlace: false,
121	    numericInput: false,
122	  },
123	  offset: {
124	    chainable: false,
125	    multipleable: false,
126	    tagOnPlace: false,
127	    numericInput: false,
128	  },
129	  'wall-join': {
130	    chainable: false,
131	    multipleable: false,
132	    tagOnPlace: false,
133	    numericInput: false,
134	  },
135	  'wall-opening': {
136	    chainable: false,
137	    multipleable: false,
138	    tagOnPlace: false,
139	    numericInput: false,
140	  },
141	  text: { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
142	  'leader-text': { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
143	  'angular-dimension': {
144	    chainable: false,
145	    multipleable: true,
146	    tagOnPlace: false,
147	    numericInput: false,
148	  },
149	  'radial-dimension': {
150	    chainable: false,
151	    multipleable: true,
152	    tagOnPlace: false,
153	    numericInput: false,
154	  },
155	  'diameter-dimension': {
156	    chainable: false,
157	    multipleable: true,
158	    tagOnPlace: false,
159	    numericInput: false,
160	  },
161	  'arc-length-dimension': {
162	    chainable: false,
163	    multipleable: true,
164	    tagOnPlace: false,
165	    numericInput: false,
166	  },
167	  'spot-elevation': {
168	    chainable: false,
169	    multipleable: true,
170	    tagOnPlace: false,
171	    numericInput: false,
172	  },
173	  'spot-coordinate': {
174	    chainable: false,
175	    multipleable: true,
176	    tagOnPlace: false,
177	    numericInput: false,
178	  },
179	  'slope-annotation': {
180	    chainable: false,
181	    multipleable: true,
182	    tagOnPlace: false,
183	    numericInput: false,
184	  },
185	  'material-tag': { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
186	  'north-arrow': { chainable: false, multipleable: false, tagOnPlace: false, numericInput: false },
187	  ramp: { chainable: false, multipleable: false, tagOnPlace: false, numericInput: true },
188	};
189	
190	/**
191	 * Numeric-input field state — appears at the cursor while a numeric-capable
192	 * tool is mid-draw and the user types a digit. `axis` toggles on Tab so a
193	 * second number can drive the perpendicular direction.
194	 */
195	export interface NumericInputState {
196	  active: boolean;
197	  value: string;
198	  axis: 'primary' | 'perpendicular';
199	}
200	
201	export function initialNumericInputState(): NumericInputState {
202	  return { active: false, value: '', axis: 'primary' };
203	}
204	
205	export type NumericInputEvent =
206	  | { kind: 'start'; firstDigit: string }
207	  | { kind: 'append'; digit: string }
208	  | { kind: 'backspace' }
209	  | { kind: 'tab-axis' }
210	  | { kind: 'commit' }
211	  | { kind: 'cancel' };
212	
213	export function reduceNumericInput(
214	  state: NumericInputState,
215	  event: NumericInputEvent,
216	): NumericInputState {
217	  switch (event.kind) {
218	    case 'start':
219	      return { active: true, value: event.firstDigit, axis: 'primary' };
220	    case 'append':
221	      if (!state.active) return state;
222	      return { ...state, value: state.value + event.digit };
223	    case 'backspace':
224	      if (!state.active) return state;
225	      return { ...state, value: state.value.slice(0, -1) };
226	    case 'tab-axis':
227	      if (!state.active) return state;
228	      return {
229	        ...state,
230	        axis: state.axis === 'primary' ? 'perpendicular' : 'primary',
231	      };
232	    case 'commit':
233	    case 'cancel':
234	      return initialNumericInputState();
235	  }
236	}
237	
238	export type ToolGrammarKind =
239	  | 'wall'
240	  | 'door'
241	  | 'window'
242	  | 'floor'
243	  | 'roof'
244	  | 'stair'
245	  | 'railing'
246	  | 'room'
247	  | 'dimension'
248	  | 'section'
249	  | 'tag'
250	  | 'align'
251	  | 'split'
252	  | 'trim'
253	  | 'offset'
254	  | 'wall-join';
255	
256	export const WALL_LOCATION_LINE_ORDER: WallLocationLine[] = [
257	  'wall-centerline',
258	  'finish-face-exterior',
259	  'finish-face-interior',
260	  'core-centerline',
261	  'core-face-exterior',
262	  'core-face-interior',
263	];
264	
265	/** Cycle through the §16.4.1 location-line set on `Tab`. */
266	export function cycleWallLocationLine(current: WallLocationLine): WallLocationLine {
267	  const idx = WALL_LOCATION_LINE_ORDER.indexOf(current);
268	  if (idx < 0) return WALL_LOCATION_LINE_ORDER[0]!;
269	  return WALL_LOCATION_LINE_ORDER[(idx + 1) % WALL_LOCATION_LINE_ORDER.length]!;
270	}
271	
272	/** Wall tool state machine — minimum necessary to drive a chain mode
273	 * without leaking pointer details into the controller. */
274	export interface WallChainState {
275	  active: boolean;
276	  startMm: { xMm: number; yMm: number } | null;
277	  /** Locked endpoint after a click; chain mode begins from here. */
278	  chainAnchorMm: { xMm: number; yMm: number } | null;
279	  locationLine: WallLocationLine;
280	}
281	
282	export function initialWallChainState(): WallChainState {
283	  return {
284	    active: false,
285	    startMm: null,
286	    chainAnchorMm: null,
287	    locationLine: 'wall-centerline',
288	  };
289	}
290	
291	export type WallChainEvent =
292	  | { kind: 'tool-activated' }
293	  | { kind: 'tool-deactivated' }
294	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
295	  | { kind: 'cancel' }
296	  | { kind: 'tab-cycle-location' }
297	  | { kind: 'enter-finish' };
298	
299	export interface WallChainEffect {
300	  /** Wall span to commit, when a 2nd click closes a segment. */
301	  commitSegment?: {
302	    startMm: { xMm: number; yMm: number };
303	    endMm: { xMm: number; yMm: number };
304	    locationLine: WallLocationLine;
305	  };
306	  /** True when the tool stays active after the event. */
307	  stillActive: boolean;
308	  /** True when this event broke the chain (Esc). */
309	  chainBroken?: boolean;
310	}
311	
312	export function reduceWallChain(
313	  state: WallChainState,
314	  event: WallChainEvent,
315	): { state: WallChainState; effect: WallChainEffect } {
316	  if (event.kind === 'tool-activated') {
317	    return {
318	      state: { ...state, active: true, startMm: null, chainAnchorMm: null },
319	      effect: { stillActive: true },
320	    };
321	  }
322	  if (event.kind === 'tool-deactivated') {
323	    return {
324	      state: { ...initialWallChainState() },
325	      effect: { stillActive: false },
326	    };
327	  }
328	  if (!state.active) {
329	    return { state, effect: { stillActive: false } };
330	  }
331	  if (event.kind === 'tab-cycle-location') {
332	    return {
333	      state: {
334	        ...state,
335	        locationLine: cycleWallLocationLine(state.locationLine),
336	      },
337	      effect: { stillActive: true },
338	    };
339	  }
340	  if (event.kind === 'cancel') {
341	    return {
342	      state: { ...state, startMm: null, chainAnchorMm: null },
343	      effect: { stillActive: true, chainBroken: true },
344	    };
345	  }
346	  if (event.kind === 'enter-finish') {
347	    return {
348	      state: { ...initialWallChainState() },
349	      effect: { stillActive: false },
350	    };
351	  }
352	  // click
353	  const start = state.chainAnchorMm ?? state.startMm;
354	  if (!start) {
355	    return {
356	      state: { ...state, startMm: event.pointMm, chainAnchorMm: null },
357	      effect: { stillActive: true },
358	    };
359	  }
360	  const segment = {
361	    startMm: start,
362	    endMm: event.pointMm,
363	    locationLine: state.locationLine,
364	  };
365	  return {
366	    state: { ...state, startMm: null, chainAnchorMm: event.pointMm },
367	    effect: { commitSegment: segment, stillActive: true },
368	  };
369	}
370	
371	/* ────────────────────────────────────────────────────────────────────── */
372	/* Door / Window — §16.4.2 / §16.4.3                                       */
373	/* ────────────────────────────────────────────────────────────────────── */
374	
375	export interface HostedOpeningDefaults {
376	  widthMm: number;
377	  heightMm: number;
378	  sillHeightMm?: number;
379	}
380	
381	export type DoorSwing = 'left' | 'right';
382	export type DoorHand = 'in' | 'out';
383	
384	export interface DoorPlacement {
385	  wallId: string;
386	  alongT: number;
387	  widthMm: number;
388	  heightMm: number;
389	  swing: DoorSwing;
390	  hand: DoorHand;
391	}
392	
393	export const DOOR_DEFAULTS: HostedOpeningDefaults & {
394	  swing: DoorSwing;
395	  hand: DoorHand;
396	} = {
397	  widthMm: 900,
398	  heightMm: 2100,
399	  swing: 'left',
400	  hand: 'in',
401	};
402	
403	/** Spacebar flips swing side; Tab flips hand. */
404	export function flipDoorSwing(swing: DoorSwing): DoorSwing {
405	  return swing === 'left' ? 'right' : 'left';
406	}
407	
408	export function flipDoorHand(hand: DoorHand): DoorHand {
409	  return hand === 'in' ? 'out' : 'in';
410	}
411	
412	export const WINDOW_DEFAULTS: HostedOpeningDefaults = {
413	  widthMm: 1200,
414	  heightMm: 1500,
415	  sillHeightMm: 900,
416	};
417	
418	/* ────────────────────────────────────────────────────────────────────── */
419	/* Floor — §16.4.4                                                          */
420	/* ────────────────────────────────────────────────────────────────────── */
421	
422	export type FloorMode = 'pick-walls' | 'sketch';
423	
424	export interface FloorState {
425	  mode: FloorMode;
426	  sketchPolygonMm: { xMm: number; yMm: number }[];
427	  pickedWallIds: string[];
428	  thicknessMm: number;
429	}
430	
431	export function initialFloorState(): FloorState {
432	  return {
433	    mode: 'pick-walls',
434	    sketchPolygonMm: [],
435	    pickedWallIds: [],
436	    thicknessMm: 220,
437	  };
438	}
439	
440	export function toggleFloorMode(mode: FloorMode): FloorMode {
441	  return mode === 'pick-walls' ? 'sketch' : 'pick-walls';
442	}
443	
444	/* ────────────────────────────────────────────────────────────────────── */
445	/* Roof — §16.4.5                                                           */
446	/* ────────────────────────────────────────────────────────────────────── */
447	
448	export type RoofType = 'gable' | 'hip' | 'flat' | 'shed';
449	
450	export interface RoofState {
451	  type: RoofType;
452	  slopeDeg: number;
453	  /** Per-edge slope override; key is edge index. */
454	  edgeSlopes: Record<number, boolean>;
455	  eaveOverhangMm: number;
456	}
457	
458	export function initialRoofState(): RoofState {
459	  return {
460	    type: 'gable',
461	    slopeDeg: 35,
462	    edgeSlopes: {},
463	    eaveOverhangMm: 600,
464	  };
465	}
466	
467	export function toggleEdgeSlope(state: RoofState, edgeIdx: number): RoofState {
468	  const next = { ...state.edgeSlopes };
469	  next[edgeIdx] = !state.edgeSlopes[edgeIdx];
470	  return { ...state, edgeSlopes: next };
471	}
472	
473	/* ────────────────────────────────────────────────────────────────────── */
474	/* Stair — §16.4.6                                                          */
475	/* ────────────────────────────────────────────────────────────────────── */
476	
477	export type StairType = 'straight' | 'l-shape' | 'u-shape' | 'spiral';
478	
479	export interface StairCalcInput {
480	  baseLevelElevMm: number;
481	  topLevelElevMm: number;
482	  preferredRiserMm?: number;
483	  preferredTreadMm?: number;
484	}
485	
486	export interface StairCalcOutput {
487	  riserMm: number;
488	  treadMm: number;
489	  riserCount: number;
490	  treadCount: number;
491	  totalRiseMm: number;
492	}
493	
494	export const STAIR_RISER_MM_DEFAULT = 175;
495	export const STAIR_TREAD_MM_DEFAULT = 280;
496	
497	/** Auto-compute risers/treads for a straight run between two levels. */
498	export function computeStairRun(input: StairCalcInput): StairCalcOutput {
499	  const totalRise = input.topLevelElevMm - input.baseLevelElevMm;
500	  if (totalRise <= 0) {
501	    return {
502	      riserMm: STAIR_RISER_MM_DEFAULT,
503	      treadMm: STAIR_TREAD_MM_DEFAULT,
504	      riserCount: 0,
505	      treadCount: 0,
506	      totalRiseMm: 0,
507	    };
508	  }
509	  const desired = input.preferredRiserMm ?? STAIR_RISER_MM_DEFAULT;
510	  const riserCount = Math.max(2, Math.round(totalRise / desired));
511	  const riserMm = totalRise / riserCount;
512	  const treadMm = input.preferredTreadMm ?? STAIR_TREAD_MM_DEFAULT;
513	  return {
514	    riserMm,
515	    treadMm,
516	    riserCount,
517	    treadCount: riserCount - 1,
518	    totalRiseMm: totalRise,
519	  };
520	}
521	
522	/* ────────────────────────────────────────────────────────────────────── */
523	/* Railing — §16.4.7                                                        */
524	/* ────────────────────────────────────────────────────────────────────── */
525	
526	export type RailingHostKind = 'stair' | 'slab-edge' | 'sketch-path';
527	
528	export interface RailingDefaults {
529	  style: 'horizontal-bars-5x30';
530	  totalHeightMm: number;
531	  baluster: {
532	    spacingMm: number;
533	    diameterMm: number;
534	  };
535	}
536	
537	export const RAILING_DEFAULTS: RailingDefaults = {
538	  style: 'horizontal-bars-5x30',
539	  totalHeightMm: 1100,
540	  baluster: { spacingMm: 100, diameterMm: 30 },
541	};
542	
543	/* ────────────────────────────────────────────────────────────────────── */
544	/* Room marker — §16.4.8                                                    */
545	/* ────────────────────────────────────────────────────────────────────── */
546	
547	export interface RoomMarkerInput {
548	  /** Closed boundary forming the room — typically the auto-detected
549	   * polygon under the cursor. */
550	  outlineMm: { xMm: number; yMm: number }[];
551	}
552	
553	export function centroidMm(outline: { xMm: number; yMm: number }[]): {
554	  xMm: number;
555	  yMm: number;
556	} {
557	  if (outline.length === 0) return { xMm: 0, yMm: 0 };
558	  let area = 0;
559	  let cx = 0;
560	  let cy = 0;
561	  for (let i = 0; i < outline.length; i++) {
562	    const a = outline[i]!;
563	    const b = outline[(i + 1) % outline.length]!;
564	    const cross = a.xMm * b.yMm - b.xMm * a.yMm;
565	    area += cross;
566	    cx += (a.xMm + b.xMm) * cross;
567	    cy += (a.yMm + b.yMm) * cross;
568	  }
569	  if (area === 0) {
570	    const sum = outline.reduce((acc, p) => ({ xMm: acc.xMm + p.xMm, yMm: acc.yMm + p.yMm }), {
571	      xMm: 0,
572	      yMm: 0,
573	    });
574	    return { xMm: sum.xMm / outline.length, yMm: sum.yMm / outline.length };
575	  }
576	  area /= 2;
577	  return { xMm: cx / (6 * area), yMm: cy / (6 * area) };
578	}
579	
580	/* ────────────────────────────────────────────────────────────────────── */
581	/* Area boundary — F-095                                                    */
582	/* ────────────────────────────────────────────────────────────────────── */
583	
584	export const AREA_BOUNDARY_CLOSE_TOLERANCE_MM = 520;
585	
586	export interface AreaBoundaryState {
587	  verticesMm: { xMm: number; yMm: number }[];
588	}
589	
590	export function initialAreaBoundaryState(): AreaBoundaryState {
591	  return { verticesMm: [] };
592	}
593	
594	export type AreaBoundaryEvent =
595	  | {
596	      kind: 'click';
597	      pointMm: { xMm: number; yMm: number };
598	      closeToleranceMm?: number;
599	    }
600	  | { kind: 'commit' }
601	  | { kind: 'cancel' };
602	
603	export interface AreaBoundaryEffect {
604	  commitBoundaryMm?: { xMm: number; yMm: number }[];
605	}
606	
607	function sameAreaBoundaryPoint(
608	  a: { xMm: number; yMm: number },
609	  b: { xMm: number; yMm: number },
610	): boolean {
611	  return Math.hypot(a.xMm - b.xMm, a.yMm - b.yMm) < 1;
612	}
613	
614	export function areaBoundaryCanClose(
615	  verticesMm: { xMm: number; yMm: number }[],
616	  pointMm: { xMm: number; yMm: number },
617	  closeToleranceMm = AREA_BOUNDARY_CLOSE_TOLERANCE_MM,
618	): boolean {
619	  const first = verticesMm[0];
620	  return (
621	    verticesMm.length >= 3 &&
622	    first !== undefined &&
623	    Math.hypot(pointMm.xMm - first.xMm, pointMm.yMm - first.yMm) <= closeToleranceMm
624	  );
625	}
626	
627	export function areaBoundaryRectangleFromDiagonal(
628	  startMm: { xMm: number; yMm: number },
629	  endMm: { xMm: number; yMm: number },
630	  minEdgeMm = 200,
631	): { xMm: number; yMm: number }[] | null {
632	  const widthMm = Math.abs(endMm.xMm - startMm.xMm);
633	  const depthMm = Math.abs(endMm.yMm - startMm.yMm);
634	  if (widthMm < minEdgeMm || depthMm < minEdgeMm) return null;
635	  const x0 = Math.min(startMm.xMm, endMm.xMm);
636	  const x1 = Math.max(startMm.xMm, endMm.xMm);
637	  const y0 = Math.min(startMm.yMm, endMm.yMm);
638	  const y1 = Math.max(startMm.yMm, endMm.yMm);
639	  return [
640	    { xMm: x0, yMm: y0 },
641	    { xMm: x1, yMm: y0 },
642	    { xMm: x1, yMm: y1 },
643	    { xMm: x0, yMm: y1 },
644	  ];
645	}
646	
647	export function reduceAreaBoundary(
648	  state: AreaBoundaryState,
649	  event: AreaBoundaryEvent,
650	): { state: AreaBoundaryState; effect: AreaBoundaryEffect } {
651	  if (event.kind === 'cancel') {
652	    return { state: initialAreaBoundaryState(), effect: {} };
653	  }
654	  if (event.kind === 'commit') {
655	    if (state.verticesMm.length >= 3) {
656	      return {
657	        state: initialAreaBoundaryState(),
658	        effect: { commitBoundaryMm: [...state.verticesMm] },
659	      };
660	    }
661	    return { state: initialAreaBoundaryState(), effect: {} };
662	  }
663	
664	  const point = event.pointMm;
665	  if (areaBoundaryCanClose(state.verticesMm, point, event.closeToleranceMm)) {
666	    return {
667	      state: initialAreaBoundaryState(),
668	      effect: { commitBoundaryMm: [...state.verticesMm] },
669	    };
670	  }
671	  const last = state.verticesMm[state.verticesMm.length - 1];
672	  if (last && sameAreaBoundaryPoint(last, point)) {
673	    return { state, effect: {} };
674	  }
675	  return {
676	    state: { verticesMm: [...state.verticesMm, point] },
677	    effect: {},
678	  };
679	}
