1860	  if (event.kind === 'activate') {
1861	    return { state: initialArrayState(), effect: { stillActive: true } };
1862	  }
1863	  if (event.kind === 'deactivate') {
1864	    return { state: initialArrayState(), effect: { stillActive: false } };
1865	  }
1866	  if (event.kind === 'cancel') {
1867	    const mode: ArrayToolMode = state.phase === 'idle' ? state.mode : 'linear';
1868	    const mtl = state.phase === 'idle' ? state.moveToLast : true;
1869	    return { state: idleState(mode, mtl), effect: { stillActive: true } };
1870	  }
1871	  if (event.kind === 'set-mode') {
1872	    const mtl = state.phase === 'idle' ? state.moveToLast : true;
1873	    return { state: idleState(event.mode, mtl), effect: { stillActive: true } };
1874	  }
1875	  if (event.kind === 'toggle-move-to-last') {
1876	    const mtl =
1877	      state.phase === 'idle'
1878	        ? state.moveToLast
1879	        : state.phase === 'pick-start' || state.phase === 'pick-end'
1880	          ? state.moveToLast
1881	          : state.phase === 'confirm-linear'
1882	            ? state.moveToLast
1883	            : true;
1884	    return { state: { ...state, moveToLast: !mtl } as ArrayState, effect: { stillActive: true } };
1885	  }
1886	
1887	  if (event.kind === 'click') {
1888	    if (state.phase === 'idle' && state.mode === 'linear') {
1889	      return {
1890	        state: { phase: 'pick-start', mode: 'linear', moveToLast: state.moveToLast },
1891	        effect: { stillActive: true },
1892	      };
1893	    }
1894	    if (state.phase === 'pick-start') {
1895	      return {
1896	        state: {
1897	          phase: 'pick-end',
1898	          mode: 'linear',
1899	          moveToLast: state.moveToLast,
1900	          startMm: { xMm: event.xMm, yMm: event.yMm },
1901	        },
1902	        effect: { stillActive: true },
1903	      };
1904	    }
1905	    if (state.phase === 'pick-end') {
1906	      return {
1907	        state: {
1908	          phase: 'confirm-linear',
1909	          moveToLast: state.moveToLast,
1910	          startMm: state.startMm,
1911	          endMm: { xMm: event.xMm, yMm: event.yMm },
1912	          count: 3,
1913	        },
1914	        effect: { stillActive: true },
1915	      };
1916	    }
1917	    if (state.phase === 'idle' && state.mode === 'radial') {
1918	      return {
1919	        state: { phase: 'pick-center', mode: 'radial' },
1920	        effect: { stillActive: true },
1921	      };
1922	    }
1923	    if (state.phase === 'pick-center') {
1924	      return {
1925	        state: {
1926	          phase: 'confirm-radial',
1927	          centerMm: { xMm: event.xMm, yMm: event.yMm },
1928	          angleDeg: 360,
1929	          count: 3,
1930	        },
1931	        effect: { stillActive: true },
1932	      };
1933	    }
1934	  }
1935	
1936	  if (event.kind === 'set-count') {
1937	    if (state.phase === 'confirm-linear') {
1938	      return { state: { ...state, count: event.count }, effect: { stillActive: true } };
1939	    }
1940	    if (state.phase === 'confirm-radial') {
1941	      return { state: { ...state, count: event.count }, effect: { stillActive: true } };
1942	    }
1943	  }
1944	
1945	  if (event.kind === 'set-angle' && state.phase === 'confirm-radial') {
1946	    return { state: { ...state, angleDeg: event.angleDeg }, effect: { stillActive: true } };
1947	  }
1948	
1949	  if (event.kind === 'confirm') {
1950	    if (state.phase === 'confirm-linear') {
1951	      return {
1952	        state: idleState('linear', state.moveToLast),
1953	        effect: {
1954	          commitLinear: {
1955	            startMm: state.startMm,
1956	            endMm: state.endMm,
1957	            count: state.count,
1958	            moveToLast: state.moveToLast,
1959	          },
1960	          stillActive: true,
1961	        },
1962	      };
1963	    }
1964	    if (state.phase === 'confirm-radial') {
1965	      return {
1966	        state: idleState('radial'),
1967	        effect: {
1968	          commitRadial: {
1969	            centerMm: state.centerMm,
1970	            angleDeg: state.angleDeg,
1971	            count: state.count,
1972	          },
1973	          stillActive: true,
1974	        },
1975	      };
1976	    }
1977	  }
1978	
1979	  return { state, effect: { stillActive: true } };
1980	}
1981	
1982	/* ────────────────────────────────────────────────────────────────────── */
1983	/* Scale Tool — B1                                                         */
1984	/* Phase 1: pick origin point                                              */
1985	/* Phase 2a: type numeric factor + Enter  (keyboard mode)                 */
1986	/* Phase 2b: pick reference point → pick destination point (graphical)    */
1987	/* ────────────────────────────────────────────────────────────────────── */
1988	
1989	export type ScaleInputMode = 'numeric' | 'graphical';
1990	
1991	export type ScaleState =
1992	  | { phase: 'idle' }
1993	  | { phase: 'pick-origin' }
1994	  | {
1995	      phase: 'enter-factor';
1996	      originMm: { xMm: number; yMm: number };
1997	      inputValue: string;
1998	    }
1999	  | {
2000	      phase: 'pick-reference';
2001	      originMm: { xMm: number; yMm: number };
2002	    }
2003	  | {
2004	      phase: 'pick-destination';
2005	      originMm: { xMm: number; yMm: number };
2006	      referenceMm: { xMm: number; yMm: number };
2007	    };
2008	
2009	export type ScaleEvent =
2010	  | { kind: 'activate' }
2011	  | { kind: 'deactivate' }
2012	  | { kind: 'cancel' }
2013	  | { kind: 'click'; xMm: number; yMm: number }
2014	  | { kind: 'set-input'; value: string }
2015	  | { kind: 'confirm' };
2016	
2017	export interface ScaleEffect {
2018	  commitScale?: {
2019	    originMm: { xMm: number; yMm: number };
2020	    factor: number;
2021	  };
2022	  commitGraphicalScale?: {
2023	    originMm: { xMm: number; yMm: number };
2024	    referenceMm: { xMm: number; yMm: number };
2025	    destinationMm: { xMm: number; yMm: number };
2026	  };
2027	  stillActive: boolean;
2028	}
2029	
2030	export function initialScaleState(): ScaleState {
2031	  return { phase: 'idle' };
2032	}
2033	
2034	export function reduceScale(
2035	  state: ScaleState,
2036	  event: ScaleEvent,
2037	): { state: ScaleState; effect: ScaleEffect } {
2038	  if (event.kind === 'activate') {
2039	    return { state: { phase: 'pick-origin' }, effect: { stillActive: true } };
2040	  }
2041	  if (event.kind === 'deactivate') {
2042	    return { state: initialScaleState(), effect: { stillActive: false } };
2043	  }
2044	  if (event.kind === 'cancel') {
2045	    return { state: { phase: 'pick-origin' }, effect: { stillActive: true } };
2046	  }
2047	
2048	  if (event.kind === 'click') {
2049	    if (state.phase === 'pick-origin') {
2050	      return {
2051	        state: {
2052	          phase: 'enter-factor',
2053	          originMm: { xMm: event.xMm, yMm: event.yMm },
2054	          inputValue: '',
2055	        },
2056	        effect: { stillActive: true },
2057	      };
2058	    }
2059	    if (state.phase === 'enter-factor') {
2060	      // Clicking while in enter-factor switches to graphical mode: this click is the reference point
2061	      return {
2062	        state: {
2063	          phase: 'pick-reference',
2064	          originMm: state.originMm,
2065	        },
2066	        effect: { stillActive: true },
2067	      };
2068	    }
2069	    if (state.phase === 'pick-reference') {
2070	      return {
2071	        state: {
2072	          phase: 'pick-destination',
2073	          originMm: state.originMm,
2074	          referenceMm: { xMm: event.xMm, yMm: event.yMm },
2075	        },
2076	        effect: { stillActive: true },
2077	      };
2078	    }
2079	    if (state.phase === 'pick-destination') {
2080	      return {
2081	        state: { phase: 'pick-origin' },
2082	        effect: {
2083	          commitGraphicalScale: {
2084	            originMm: state.originMm,
2085	            referenceMm: state.referenceMm,
2086	            destinationMm: { xMm: event.xMm, yMm: event.yMm },
2087	          },
2088	          stillActive: true,
2089	        },
2090	      };
2091	    }
2092	  }
2093	
2094	  if (event.kind === 'set-input' && state.phase === 'enter-factor') {
2095	    return { state: { ...state, inputValue: event.value }, effect: { stillActive: true } };
2096	  }
2097	
2098	  if (event.kind === 'confirm' && state.phase === 'enter-factor') {
2099	    const factor = parseFloat(state.inputValue.trim());
2100	    if (!Number.isFinite(factor) || factor <= 0) {
2101	      return { state, effect: { stillActive: true } };
2102	    }
2103	    return {
2104	      state: { phase: 'pick-origin' },
2105	      effect: {
2106	        commitScale: { originMm: state.originMm, factor },
2107	        stillActive: true,
2108	      },
2109	    };
2110	  }
2111	
2112	  return { state, effect: { stillActive: true } };
2113	}
