12	function elementBoundsXY(
13	  el: Element,
14	): { minX: number; maxX: number; minY: number; maxY: number } | null {
15	  if (el.kind === 'wall') {
16	    return {
17	      minX: Math.min(el.start.xMm, el.end.xMm),
18	      maxX: Math.max(el.start.xMm, el.end.xMm),
19	      minY: Math.min(el.start.yMm, el.end.yMm),
20	      maxY: Math.max(el.start.yMm, el.end.yMm),
21	    };
22	  }
23	  if ('xMm' in el && 'yMm' in el) {
24	    const x = (el as { xMm: number }).xMm;
25	    const y = (el as { yMm: number }).yMm;
26	    return { minX: x - 200, maxX: x + 200, minY: y - 200, maxY: y + 200 };
27	  }
28	  if ('insertionPoint' in el) {
29	    const ip = (el as { insertionPoint: { xMm: number; yMm: number } }).insertionPoint;
30	    return { minX: ip.xMm - 200, maxX: ip.xMm + 200, minY: ip.yMm - 200, maxY: ip.yMm + 200 };
31	  }
32	  return null;
33	}
34	
35	/**
36	 * Builds a dashed-rectangle plan glyph for a group instance.
37	 * The rectangle is the axis-aligned bounding box of the definition's member
38	 * elements, transformed by the instance insertion offset.
39	 */
40	export function buildGroupInstancePlanMesh(
41	  instance: GroupInstance,
42	  definition: GroupDefinition,
43	  elementsById: Record<string, Element>,
44	  selectedId: string | undefined,
45	): THREE.Object3D {
46	  const group = new THREE.Group();
47	  group.userData.bimPickId = instance.id;
48	
49	  // Compute bounding box of definition members in world coords.
50	  let minX = Infinity,
51	    maxX = -Infinity,
52	    minY = Infinity,
53	    maxY = -Infinity;
54	
55	  const offsetX = instance.insertionXMm - definition.originXMm;
56	  const offsetY = instance.insertionYMm - definition.originYMm;
57	
58	  for (const elId of definition.elementIds) {
59	    const el = elementsById[elId];
60	    if (!el) continue;
61	    const b = elementBoundsXY(el);
62	    if (!b) continue;
63	    minX = Math.min(minX, b.minX + offsetX);
64	    maxX = Math.max(maxX, b.maxX + offsetX);
65	    minY = Math.min(minY, b.minY + offsetY);
66	    maxY = Math.max(maxY, b.maxY + offsetY);
67	  }
68	
69	  // Fall back to a 1000 mm box at the insertion point when no members resolve.
70	  if (!isFinite(minX)) {
71	    const cx = instance.insertionXMm;
72	    const cy = instance.insertionYMm;
73	    minX = cx - 500;
74	    maxX = cx + 500;
75	    minY = cy - 500;
76	    maxY = cy + 500;
77	  }
78	
79	  const pad = 150;
80	  minX -= pad;
81	  maxX += pad;
82	  minY -= pad;
83	  maxY += pad;
84	
85	  const isSelected = instance.id === selectedId;
86	  const color = isSelected ? GROUP_SELECTED_COLOR : GROUP_DASH_COLOR;
87	
88	  const corners = [
89	    new THREE.Vector3(ux(minX), PLAN_Y + 0.008, uz(minY)),
90	    new THREE.Vector3(ux(maxX), PLAN_Y + 0.008, uz(minY)),
91	    new THREE.Vector3(ux(maxX), PLAN_Y + 0.008, uz(maxY)),
92	    new THREE.Vector3(ux(minX), PLAN_Y + 0.008, uz(maxY)),
93	    new THREE.Vector3(ux(minX), PLAN_Y + 0.008, uz(minY)),
94	  ];
95	
96	  const geo = new THREE.BufferGeometry().setFromPoints(corners);
97	  const mat = new THREE.LineDashedMaterial({
98	    color,
99	    dashSize: GROUP_DASH_SIZE,
100	    gapSize: GROUP_GAP_SIZE,
101	    depthTest: false,
102	  });
103	  const line = new THREE.Line(geo, mat);
104	  line.computeLineDistances();
105	  line.renderOrder = 8;
106	  line.userData.bimPickId = instance.id;
107	  group.add(line);
108	
109	  return group;
110	}
